// reflect-metadata kitabxanasını idxal et
// Bu nümunəni saytımızdakı redaktorda yoxlamaq üçün əlavə kitabxana tələb oluna bilər
import 'reflect-metadata';

// Sadə parametr dekoratoru
function logParameter(target: any, propertyKey: string, parameterIndex: number) {
  const existingParameters = Reflect.getMetadata('logParameters', target, propertyKey) || [];
  existingParameters.push(parameterIndex);
  Reflect.defineMetadata('logParameters', existingParameters, target, propertyKey);
}

class Person {
  greet(@logParameter message: string): string {
    return `Hello, ${message}!`;
  }
}

// Metadata-nı oxumaq
const person = new Person();
const loggedParameters = Reflect.getMetadata('logParameters', Person.prototype, 'greet') || [];
console.log(`Logged parameters for greet: ${loggedParameters}`); // Logged parameters for greet: 0
console.log(person.greet('World')); // Hello, World!

