// Parametr dekoratoru
function requiredParameter(target: any, propertyKey: string, parameterIndex: number) {
  const requiredParams = Reflect.getMetadata('requiredParameters', target, propertyKey) || [];
  requiredParams.push(parameterIndex);
  Reflect.defineMetadata('requiredParameters', requiredParams, target, propertyKey);
